let users = flow.get('users');
if (!users) { users = { alice: 'alice123', bob: 'bob123' }; flow.set('users', users); }
let socketToUser = flow.get('socketToUser') || {};
let userToSession = flow.get('userToSession') || {};
const sid = msg._session && msg._session.id;
let data;
try { data = JSON.parse(msg.payload); } catch (e) { return [null, null]; }
const reply = (obj) => { msg.payload = JSON.stringify(obj); return msg; };

if (data.type === 'login') {
  if (users[data.username] && users[data.username] === data.password) {
    socketToUser[sid] = data.username;
    flow.set('socketToUser', socketToUser);
    return [null, reply({ type: 'login-ok', user: data.username })];
  }
  return [null, reply({ type: 'login-fail' })];
}

const user = socketToUser[sid];
if (!user) return [null, reply({ type: 'need-login' })];

msg.correlationId = sid;
if (data.type === 'prompt') {
  msg.payload = data.text;
  if (userToSession[user]) msg.sessionId = userToSession[user];
  return [msg, null];
}
if (data.type === 'response') {
  msg.claudeResponse = { requestId: data.requestId, behavior: data.behavior, answers: data.answers, message: data.message };
  return [msg, null];
}
if (data.type === 'interrupt') {
  msg.claudeControl = 'interrupt';
  return [msg, null];
}
return [null, null];

const out = msg.output || {};
const sid = out.correlationId;
if (out.sessionId && sid) {
  const socketToUser = flow.get('socketToUser') || {};
  const user = socketToUser[sid];
  if (user) {
    const userToSession = flow.get('userToSession') || {};
    userToSession[user] = out.sessionId;
    flow.set('userToSession', userToSession);
  }
}
if (sid) msg._session = { type: 'websocket', id: sid };
const type = out.kind === 'result' ? 'result' : 'chunk';
msg.payload = JSON.stringify({ type, text: out.text });
return msg;

const out = msg.output || {};
const sid = out.correlationId;
if (sid) msg._session = { type: 'websocket', id: sid };
msg.payload = JSON.stringify(Object.assign({ type: 'ask' }, out.request));
return msg;

const e = msg.error || {};
const sid = e.correlationId || msg.correlationId;
if (sid) msg._session = { type: 'websocket', id: sid };
const errs = Array.isArray(e.errors) ? e.errors.join('; ') : '';
const detail = errs || e.subtype || e.message || 'run failed';
msg.payload = JSON.stringify({ type: 'error', text: detail, subtype: e.subtype, errors: e.errors });
return msg;
